CREATE TRIGGER [dbo].[PartItemAttributeType_History]ON [dbo].[PartItemAttributeType]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.PartItemAttributeTypeId IS NOT NULL AND d.PartItemAttributeTypeId IS NULL THEN 'I' 		WHEN i.PartItemAttributeTypeId IS NOT NULL AND d.PartItemAttributeTypeId IS NOT NULL THEN 'U' 		WHEN i.PartItemAttributeTypeId IS NULL AND d.PartItemAttributeTypeId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.PartItemAttributeTypeId = d.PartItemAttributeTypeId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_PartItemAttributeType([PartItemAttributeTypeId], [PartId], [ItemAttributeTypeId], [IsRequired], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [PartItemAttributeTypeId], [PartId], [ItemAttributeTypeId], [IsRequired], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_PartItemAttributeType([PartItemAttributeTypeId], [PartId], [ItemAttributeTypeId], [IsRequired], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [PartItemAttributeTypeId], [PartId], [ItemAttributeTypeId], [IsRequired], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND